mapper.select:
SELECT p.id, p.name, p.code, p.scope_type, p.tenant_id, t.name AS tenant_name,
       p.description, p.enabled, p.created_at, p.updated_at
FROM provider p LEFT JOIN tenant t ON t.id = p.tenant_id
WHERE p.deleted_at IS NULL

AND (p.name ILIKE CONCAT('%',#{keyword},'%') OR p.code ILIKE CONCAT('%',#{keyword},'%'))
AND p.scope_type = #{scopeType}
AND p.enabled = #{enabled}
ORDER BY p.created_at DESC, p.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM provider p WHERE p.deleted_at IS NULL

AND (p.name ILIKE CONCAT('%',#{keyword},'%') OR p.code ILIKE CONCAT('%',#{keyword},'%'))
AND p.scope_type = #{scopeType}
AND p.enabled = #{enabled}
